INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('gaab_maccarini', '{"name":"Gabriela Maccarini","mapped_name":"gaab_maccarini","birth_date":"1992-03-17","profession":null,"sports_history":"De uma forma ou de outra sempre fiz exercício físico, me identifico mais com a dinâmica do Cross. Não gosto da monotomia ou a quantidade de gente de academia normal, por isso, quero fazer esse treino com os aparelhos em casa.\nSinto que preciso de mais alongamento também.","injuries":["A parte inferior a coluna faz um \"clec\" dependendo do tipo de abdominal. Tendinite na pata de ganso dos dois joelhos.","Ps: tenho começado a sentir dores nas costas no geral","então acho que seria legal fortalecer toda a musculatura","até por postura e pensando a longo prazo"],"health_conditions":["Meu cardio sempre foi muuito ruim"],"medications":[],"current_practice":"Como disse, desde sempre. Mas tem uns dois meses que tenho feito exercícios em casa com a ajuda do YouTube. Se precisar, posso mandar as referências.","goal":"Saúde, Estética, Autoestima","weekly_frequency":3,"session_duration":null,"gender":"F","experience_level":"intermediário","form_timestamp":"2022/07/21 5:43:00 PM GMT-3"}'::jsonb, '{"A":{"format":"CrossFit","content":["Treino A Gab Maccarini","Treino C Gab Maccarini","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Lombar","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Lombar","3 Séries em 6'':\n10 Deadlifts (barra + elástico médio)\n5 Remadas Curvadas (barra + elástico médio)\n15 Elevação Pélvica (band médio)\n15 Superman","3 Séries em 9'':\n10 Deadlifts (barra + elástico médio)\n5 Remadas Curvadas (barra + elástico médio)\n15 Elevação Pélvica (band pesado)\n15 Flexões de joelho no Slide","WOD: \nEMOM 40\"ON / 20\"OFF por 15''\n1) Single Under\n2) Deadlift (barra + elástico pesado)\n3) Remada TRX (tronco a 45° puxando as mãos perto das costelas)","WOD: \nEMOM 45\"ON / 15\" OFF por 12''\n1) 20 Single Under + 10 Abdominal Crunch\n2) Deadlift (barra + elástico pesado e leve juntos)\n3) Remada TRX (tronco a 45° puxando as mãos em pronação com cotovelos abertos)","Treino B Gab Maccarini","Treino D Gab Maccarini","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Lombar","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Peito (barriga para baixo deitando em cima do braço)","4 Séries em 6'':\n10 Front Squats (barra + elástico leve)\n5 Flexões de Braço\n15 Abdominais Curtos (Crunch)","4 Séries em 8'':\n10 Front Squats (barra + elástico leve)\n5 Flexões de Braço\n15 Abdominais Curtos (Crunch)\n20\" Prancha Frontal","WOD: \nEMOM 40\"ON / 20\"OFF por 15''\n1) Burpee (focando no push, sem \"minhocar\")\n2) Front Squat (barra + elástico médio)\n3) Prancha Frontal alternando o levantamento dos pés no chão","WOD: \nEMOM 45\"ON / 15\"OFF por 12''\n1) 3 Burpee (focando no push, sem \"minhocar\") + 6 Abdominais Remada\n2) Front Squat (barra + elástico pesado)\n3) Prancha Frontal alternando o levantamento dos pés no chão","Treino E Gab Maccarini","Treino G Gab Maccarini","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Lombar","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Lombar","4 Séries em 10'': \n12 Pull Downs (Barra suspensa em suporte alto)\n12 Flexões de joelho no Slide","3 Séries em 9'':\n10 Deadlifts (barra + elástico médio)\n5 Remadas Curvadas (barra + elástico médio)\n15 Elevação Pélvica (band pesado)\n15 Flexões de joelho no Slide","WOD: \nAMRAP 16''\n16 Remadas Curvadas (barra + elástico pesado)\n16 Sit Ups\n32 Single Unders","WOD: \nEMOM 45\"ON / 15\" OFF por 12''\n1) 20 Single Under + 10 Abdominal Crunch\n2) Deadlift (barra + elástico pesado e leve juntos)\n3) Remada TRX (tronco a 45° puxando as mãos em pronação com cotovelos abertos)","Treino F Gab Maccarini","Treino H Gab Maccarini","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Peito (barriga para baixo deitando em cima do braço)","Aquecimento Articular:\nPunhos, cotovelos, ombros, tronco, quadris, joelhos e tornozelos.","Mobilidade (alongamento por 1''):\nPsoas; Glúteos; Posteriores de Coxa, Adutores (borboleta) e Peito (barriga para baixo deitando em cima do braço)","2 Séries em 8'':\n12 Front Squats (barra + elástico médio)\n6 Flexões de Braço\n12 Abdominais Remada\n30\" Prancha Frontal","4 Séries em 8'':\n10 Front Squats (barra + elástico leve)\n5 Flexões de Braço\n15 Abdominais Curtos (Crunch)\n20\" Prancha Frontal","WOD: 8 ROUNDS\nEMOM 1''ON / 30\"OFF por 12''\n1) 4 Burpees (focando no push, sem \"minhocar\") + 8 Abdominais Remada\n2) 8 Front Squats (barra + elástico médio) + 8 Avanços\n3) Prancha Frontal alternando o levantamento dos pés no chão","WOD: \nEMOM 45\"ON / 15\"OFF por 12''\n1) 3 Burpee (focando no push, sem \"minhocar\") + 6 Abdominais Remada\n2) Front Squat (barra + elástico pesado)\n3) Prancha Frontal alternando o levantamento dos pés no chão"],"exercises":[]},"C":{"format":"CrossFit","content":["TREINO A\nMEMBROS SUPERIORES\nHIPERTROFIA MUSCULAR","NOME DO ALUNO","Exercícios","Método","Variáveis","SÉRIE 1","SÉRIE 2","SÉRIE 3","Supino","Drop-set","Rep","Peso","Pausa","Cadência","RIR","Crucifixo","Strip-set","Rep","Peso","Pausa","Cadência","RIR","Desenvolvimento","HIRT","Rep","Peso","Pausa","Cadência","RIR","Elevação lateral","Drop-set","Rep","Peso","Pausa","Cadência","RIR","Tríceps Testa","Strip-set","Rep","Peso","Pausa","Cadência","RIR","Tríceps Pulley","HIRT","Rep","Peso","Pausa","Cadência","RIR"],"exercises":[]},"D":{"format":"CrossFit","content":["TREINO A\nMEMBROS SUPERIORES\nHIPERTROFIA MUSCULAR","NOME DO ALUNO","Exercícios","Método","Variáveis","SÉRIE 1","SÉRIE 2","SÉRIE 3","Supino","Drop-set","Rep","Peso","Pausa","Cadência","RIR","Crucifixo","Strip-set","Rep","Peso","Pausa","Cadência","RIR","Desenvolvimento","HIRT","Rep","Peso","Pausa","Cadência","RIR","Elevação lateral","Drop-set","Rep","Peso","Pausa","Cadência","RIR","Tríceps Testa","Strip-set","Rep","Peso","Pausa","Cadência","RIR","Tríceps Pulley","HIRT","Rep","Peso","Pausa","Cadência","RIR"],"exercises":[]},"E":{"format":"CrossFit","content":["TREINO A\nMEMBROS SUPERIORES\nHIPERTROFIA MUSCULAR","NOME DO ALUNO","Exercícios","Método","Variáveis","SÉRIE 1","SÉRIE 2","SÉRIE 3","Supino","Drop-set","Rep","Peso","Pausa","Cadência","RIR","Crucifixo","Strip-set","Rep","Peso","Pausa","Cadência","RIR","Desenvolvimento","HIRT","Rep","Peso","Pausa","Cadência","RIR","Elevação lateral","Drop-set","Rep","Peso","Pausa","Cadência","RIR","Tríceps Testa","Strip-set","Rep","Peso","Pausa","Cadência","RIR","Tríceps Pulley","HIRT","Rep","Peso","Pausa","Cadência","RIR"],"exercises":[]}}'::jsonb, ARRAY['A','C','D','E']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;